+fn normalize_one_command(command: &str) -> Option<String> {
+    let normalized = command.trim();
+    if normalized.is_empty() || normalized.contains('\n') || normalized.contains('\r') {
+        return None;
+    }
+    Some(normalized.to_owned())
+}
